func (this *BtcturkCore) ParseOrderStatus(status any) any {
	var statuses any = map[string]any{
		"Untouched": "open",
		"Partial":   "open",
		"Canceled":  "canceled",
		"Closed":    "closed",
	}
	return this.SafeString(statuses, status, status)
}
func (this *BtcturkCore) ParseOrder(order any, optionalArgs ...any) any {
	//
	// fetchOrders / fetchOpenOrders
	//     {
	//       "id": 2605984008,
	//       "price": "55000",
	//       "amount": "0.00050000",
	//       "quantity": "0.00050000",
	//       "stopPrice": "0",
	//       "pairSymbol": "BTCUSDT",
	//       "pairSymbolNormalized": "BTC_USDT",
	//       "type": "buy",
	//       "method": "limit",
	//       "orderClientId": "f479bdb6-0965-4f03-95b5-daeb7aa5a3a5",
	//       "time": 0,
	//       "updateTime": 1618913083543,
	//       "status": "Untouched",
	//       "leftAmount": "0.00050000"
	//     }
	//
	// createOrder
	//     {
	//       "id": "2606935102",
	//       "quantity": "0.0002",
	//       "price": "56000",
	//       "stopPrice": null,
	//       "newOrderClientId": "98e5c491-7ed9-462b-9666-93553180fb28",
	//       "type": "buy",
	//       "method": "limit",
	//       "pairSymbol": "BTCUSDT",
	//       "pairSymbolNormalized": "BTC_USDT",
	//       "datetime": "1618916479523"
	//     }
	//
	market := GetArg(optionalArgs, 0, nil)
	_ = market
	var id any = this.SafeString(order, "id")
	var price any = this.SafeString(order, "price")
	var amountString any = this.SafeString2(order, "amount", "quantity")
	var amount any = Precise.StringAbs(amountString)
	var remaining any = this.SafeString(order, "leftAmount")
	var marketId any = this.SafeString(order, "pairSymbol")
	var symbol any = this.SafeSymbol(marketId, market)
	var side any = this.SafeString(order, "type")
	var typeVar any = this.SafeString(order, "method")
	var clientOrderId any = this.SafeString(order, "orderClientId")
	var timestamp any = this.SafeInteger2(order, "updateTime", "datetime")
	var rawStatus any = this.SafeString(order, "status")
	var status any = this.ParseOrderStatus(rawStatus)
	return this.SafeOrder(map[string]any{
		"info":          order,
		"id":            id,
		"price":         price,
		"amount":        amount,
		"remaining":     remaining,
		"filled":        nil,
		"cost":          nil,
		"average":       nil,
		"status":        status,
		"side":          side,
		"type":          typeVar,
		"clientOrderId": clientOrderId,
		"timestamp":     timestamp,
		"datetime":      this.Iso8601(timestamp),
		"symbol":        symbol,
		"fee":           nil,
	}, market)
}

